import type { ScenarioQuestion } from "./types";

function q(id: string, group: string, sub: string, scenario: string, question: string, answer: string, feedback: string, diff: "beginner" | "intermediate" | "advanced"): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: group, subcategory: sub, scenarioPrompt: scenario, question, exampleAnswer: answer, feedback, difficulty: diff };
}

export const expandedBatch1: ScenarioQuestion[] = [
  q("sq-ex1-1", "interview_preparation", "behavioral", "You are asked to describe your biggest accomplishment in nursing school.", "What was your most significant achievement during clinical training?", "During my capstone rotation in the ICU, I identified early signs of sepsis in a patient that the team had not yet noticed. I presented my assessment findings using SBAR to the attending physician, who ordered blood cultures and started broad-spectrum antibiotics. The patient's condition stabilized within 24 hours. My preceptor commended my clinical judgment and assessment skills.", "Specific clinical examples with measurable outcomes are most impactful.", "beginner"),
  q("sq-ex1-2", "interview_preparation", "behavioral", "Tell me about a time you received negative feedback.", "Describe how you handled constructive criticism.", "My preceptor told me my IV insertion technique needed improvement after several failed attempts. Instead of becoming defensive, I asked for specific guidance, watched training videos, and practiced on simulation models during my own time. Within two weeks, my success rate improved significantly. I learned that feedback is a gift that accelerates growth.", "Shows resilience, initiative, and concrete improvement actions.", "beginner"),
  q("sq-ex1-3", "interview_preparation", "clinical_judgment", "A patient on an insulin drip has a blood glucose of 52 mg/dL and is asymptomatic.", "What would you do for this hypoglycemic patient on an insulin drip?", "I would stop the insulin drip immediately, follow the hypoglycemia protocol by administering D50 if the patient has IV access, recheck the glucose in 15 minutes, and notify the provider. Even though the patient is asymptomatic, a glucose of 52 is dangerously low and can deteriorate rapidly. I would monitor closely and anticipate insulin drip rate adjustment.", "Immediate action even with asymptomatic patient—do not wait for symptoms.", "intermediate"),
  q("sq-ex1-4", "interview_preparation", "clinical_judgment", "A post-operative patient has not voided in 8 hours and reports lower abdominal pressure.", "How would you assess and manage urinary retention?", "I would first perform a bladder scan to determine bladder volume. If greater than 300-400 mL, I would anticipate the need for straight catheterization. I would encourage the patient to try voiding naturally first by running water, providing privacy, and positioning comfortably. I would notify the provider of the retention and document the assessment and interventions.", "Systematic assessment before intervention, least invasive approach first.", "beginner"),
  q("sq-ex1-5", "interview_preparation", "scenario_responses", "A co-worker tells you they saw a patient's family member stealing supplies from the supply room.", "How would you handle a report of theft on your unit?", "I would take the report seriously and inform the charge nurse immediately. I would not confront the family member myself. I would document what was reported to me, including the time and specifics. The charge nurse would determine whether to involve security. I would also assess whether the family might have a legitimate need that could be addressed through other means.", "Proper chain of communication and avoiding direct confrontation.", "intermediate"),
  q("sq-ex1-6", "interview_preparation", "star_examples", "Tell me about a time you had to learn something new quickly.", "Describe how you adapted to learning a new skill under pressure.", "During my clinical rotation, our unit received a patient requiring continuous bladder irrigation, which I had only read about. I quickly reviewed the procedure in my clinical reference app, asked my preceptor to walk me through the setup, and took detailed notes. I managed the CBI independently by the next shift, including monitoring irrigation flow and output. My willingness to learn quickly was noted in my clinical evaluation.", "Rapid learning combined with appropriate resource use and follow-through.", "beginner"),
  q("sq-ex1-7", "interview_preparation", "common_nursing_interview", "The interviewer asks: 'How do you handle stress?'", "What are your stress management strategies?", "I manage stress through a combination of preparation and self-care. Before each shift, I review my patients to feel prepared. During the shift, I use prioritization and deep breathing during high-pressure moments. After challenging shifts, I debrief with colleagues and journal about my experiences. I also maintain work-life balance through exercise, hobbies, and spending time with supportive people. I have learned that managing stress is a skill that improves with practice.", "Specific, actionable strategies rather than vague statements.", "beginner"),
  q("sq-ex1-8", "interview_preparation", "common_nursing_interview", "The interviewer asks: 'What unit are you most interested in and why?'", "Why are you interested in this specific unit?", "I am drawn to this unit because of the patient population complexity, the collaborative team culture I have heard about, and the learning opportunities it provides. During my clinical rotation in a similar setting, I discovered that I thrive in environments that require critical thinking and quick decision-making. I have also researched your new graduate residency program and believe it would give me the foundation I need to become an excellent nurse on this unit.", "Specific reasons that connect personal interests to the unit's strengths.", "beginner"),
  q("sq-ex1-9", "interview_preparation", "difficult_interviewer", "The interviewer asks: 'What would you do if you saw a physician doing something unethical?'", "How would you handle witnessing unethical behavior by a physician?", "I would first ensure patient safety is not immediately at risk. I would document what I observed with specific details. I would report through the appropriate channels—my charge nurse, nurse manager, and if needed, the ethics committee. I would not be intimidated by the physician's position, because my primary obligation is to my patients and my professional ethics. I would follow up to ensure the report was addressed.", "Principled stance regardless of hierarchy, with proper documentation and reporting.", "advanced"),
  q("sq-ex1-10", "interview_preparation", "panel_interview", "A panel member asks you to role-play giving an SBAR report.", "Please give us an SBAR report for a deteriorating patient.", "Situation: I am calling about Mrs. Johnson in room 412. She is a 72-year-old admitted for community-acquired pneumonia. Background: She has a history of COPD and heart failure. She has been on IV levofloxacin for 24 hours and 2L nasal cannula. Assessment: In the last hour, her respiratory rate increased from 18 to 28, oxygen saturation dropped from 95% to 88% on 2L, she has become more confused, and I am hearing increased crackles bilaterally. Recommendation: I have increased her oxygen to 4L and would like you to assess her. I think she may need a chest X-ray and ABG.", "Structured, concise, and clinically complete SBAR with clear recommendation.", "intermediate"),
  q("sq-ex1-11", "workplace_scenarios", "prioritization", "You are responsible for three patients needing blood draws, two patients due for medication, and a new admission arriving.", "How would you organize multiple simultaneous tasks?", "I would draw blood first for the patients whose results are needed for clinical decisions today. I would then administer the medications, starting with the time-critical ones. I would begin the admission process once urgent tasks are addressed, delegating vital signs and room setup to the CNA. I would keep the charge nurse informed about the admission timeline.", "Task organization based on clinical impact and effective delegation.", "intermediate"),
  q("sq-ex1-12", "workplace_scenarios", "delegation", "You need help repositioning a bariatric patient but no one responds to your request.", "How would you handle inability to get help for a physically demanding task?", "I would not attempt to reposition the patient alone, as this could injure both me and the patient. I would use the call bell system or overhead page for help. I would contact the charge nurse directly. I would check if assistive devices like a Hoyer lift or ceiling lift are available. Patient and staff safety are both priorities—no task is worth a back injury.", "Never compromise safety by attempting tasks alone that require assistance.", "beginner"),
  q("sq-ex1-13", "workplace_scenarios", "patient_safety", "A patient's wristband has fallen off and you need to administer their medication.", "What would you do if a patient's identification band is missing?", "I would not administer the medication without proper identification. I would use two patient identifiers—asking the patient to state their full name and date of birth. I would then replace the wristband immediately. I would document the incident and report the missing band to the charge nurse to prevent future identification issues.", "Two patient identifiers are always required before any intervention.", "beginner"),
  q("sq-ex1-14", "workplace_scenarios", "medication_error", "You realize you calculated a pediatric medication dose incorrectly, but fortunately caught it before administration.", "How would you handle a near-miss medication calculation error?", "Even though no harm occurred, I would document the near-miss through the incident reporting system. Near-misses are valuable learning opportunities that can prevent actual errors. I would review my calculation process to identify where the error occurred, implement a double-check strategy for pediatric calculations going forward, and share the learning with my team during a safety huddle.", "Near-misses are just as important to report as actual errors for system improvement.", "intermediate"),
  q("sq-ex1-15", "workplace_scenarios", "handoff_communication", "You are giving a telephone report to a physician who seems impatient and keeps interrupting you.", "How would you ensure complete communication when the listener is impatient?", "I would remain calm and concise while ensuring all critical information is conveyed. I would prioritize the most important information first and use a structured format like SBAR to stay organized. If interrupted, I would politely redirect: 'I just have two more important points to share.' I would read back any verbal orders to ensure accuracy, even if the physician seems rushed.", "Structured communication and assertive read-back despite time pressure.", "intermediate"),
  q("sq-ex1-16", "workplace_scenarios", "difficult_coworkers", "A colleague consistently takes personal calls during their shift, leaving you to cover their patients.", "How would you address a colleague who is not pulling their weight?", "I would first address it directly and privately: 'I have noticed you have been taking frequent personal calls, and I am covering your patients during those times. Is everything okay?' There may be a personal situation I am not aware of. If the behavior continues after our conversation, I would bring it to the charge nurse's attention with specific examples and focus on the impact on patient care.", "Direct communication first, then escalation with specific examples.", "intermediate"),
  q("sq-ex1-17", "workplace_scenarios", "interdisciplinary_communication", "The pharmacist questions your medication administration timing, suggesting you are giving doses at the wrong intervals.", "How would you respond to a pharmacist questioning your practice?", "I would listen to the pharmacist's concern and review the medication schedule together. Pharmacists are medication experts, and their input is valuable. If I was following the correct schedule, I would show them my documentation. If they identified an error in the ordering, we would work together to contact the provider for clarification. I would view this as collaborative safety checking.", "Valuing pharmacist expertise and collaborative problem-solving.", "beginner"),
  q("sq-ex1-18", "clinical_transition", "first_shift", "You arrive at work and discover you are assigned to a patient who passed away on the previous shift.", "How would you handle being assigned to a room where a patient recently died?", "I would first process any emotional impact the news has on me. I would check whether the room needs to be cleaned and prepared for a new admission. I would ask about any family members who may still be present and offer appropriate support. If the death is affecting me emotionally, I would briefly discuss it with my charge nurse. I would then focus on preparing for whatever comes next—a new admission or supporting neighboring patients.", "Emotional processing, practical readiness, and professional composure.", "beginner"),
  q("sq-ex1-19", "clinical_transition", "new_nurse_anxiety", "You made a minor charting error and your preceptor corrected you in front of other staff members.", "How would you handle public correction by your preceptor?", "I would maintain composure in the moment and thank my preceptor for catching the error. Later, I would have a private conversation: 'I appreciate the correction, but I would prefer to receive feedback privately when possible, as it helps me learn more effectively.' I would not dwell on the embarrassment but would focus on the lesson learned. If the behavior continued, I would discuss it with my nurse educator.", "Professional handling of public correction with appropriate private follow-up.", "beginner"),
  q("sq-ex1-20", "clinical_transition", "time_management", "You have a patient who talks extensively during every interaction, consuming a lot of your limited time.", "How would you manage a talkative patient while maintaining your schedule?", "I would set gentle time boundaries at the start of each interaction: 'I have about 10 minutes right now, and I want to make sure we cover everything important.' I would use active listening and redirect conversations to relevant topics. I would schedule longer interactions when my workload allows. I would also assess whether the excessive talking is a sign of loneliness, anxiety, or confusion that needs to be addressed.", "Compassionate time management with therapeutic communication skills.", "beginner"),
  q("sq-ex1-21", "clinical_transition", "documentation_challenges", "You witness a colleague documenting care that was not actually provided.", "How would you handle witnessing falsified documentation?", "I would not ignore it, as falsified documentation is a serious legal and ethical violation that could harm patients. I would speak with the colleague privately first to give them the opportunity to correct it. If they refused, I would report it to the charge nurse and manager. I would document my own observations accurately. Falsifying records can result in license revocation and legal liability.", "Zero tolerance for documentation falsification with appropriate reporting.", "advanced"),
  q("sq-ex1-22", "clinical_transition", "critical_thinking_drills", "A patient's serum troponin comes back elevated at 0.5 ng/mL.", "What is the clinical significance of an elevated troponin?", "An elevated troponin indicates myocardial injury and is a key biomarker for acute coronary syndrome including myocardial infarction. I would assess the patient for cardiac symptoms such as chest pain, shortness of breath, and diaphoresis. I would obtain a 12-lead ECG, notify the provider immediately, ensure continuous cardiac monitoring, establish IV access, and prepare for possible intervention. Serial troponins would be needed to assess the trend.", "Recognizing cardiac biomarker significance and implementing appropriate interventions.", "intermediate"),
  q("sq-ex1-23", "professional_development", "professional_boundaries", "A patient asks you to share your opinion about whether their physician is competent.", "How would you respond to a patient questioning their physician's competence?", "I would not make judgments about a colleague's competence to a patient. I would say, 'Dr. Smith is a qualified physician on our medical staff. If you have specific concerns about your care, I can help you speak with the patient advocate or your charge nurse.' I would also notify the physician if the patient has concerns so they can address them directly.", "Supporting colleagues while directing patients to proper advocacy channels.", "intermediate"),
  q("sq-ex1-24", "professional_development", "ethical_dilemmas", "You are caring for an elderly patient with a DNR order, and the family is present when the patient stops breathing.", "How would you honor a DNR when the family is panicking?", "I would calmly but firmly explain that the patient has a Do Not Resuscitate order, which means we will not perform CPR. I would provide comfort measures and stay with the family. I would validate their distress while honoring the patient's wishes. I would call the physician to pronounce death and offer pastoral care. If the family demands CPR despite the DNR, I would explain that I am legally and ethically obligated to follow the order.", "Calm, compassionate communication during an emotionally charged moment.", "advanced"),
  q("sq-ex1-25", "professional_development", "workplace_bullying", "A group of experienced nurses intentionally withholds important patient information from you during handoff.", "How would you handle being intentionally excluded from clinical information?", "I would not rely solely on verbal report. I would independently review each patient's chart, recent orders, lab results, and medication administration record. I would ask direct questions about specific clinical concerns. I would document any instances of incomplete handoff and escalate to my manager if the pattern continues, as this behavior directly threatens patient safety.", "Independent verification and escalation for patient safety.", "intermediate"),
  q("sq-ex1-26", "professional_development", "advocacy", "A non-English-speaking patient is not receiving adequate interpreter services and is consenting to procedures they may not understand.", "How would you advocate for language access rights?", "I would stop any consent process that I believe the patient does not fully understand. I would request a certified medical interpreter and refuse to accept family members as interpreters for consent discussions. I would educate the team about language access requirements and patient rights. I would document my advocacy and any barriers I encountered.", "Patient rights advocacy requires action, not just observation.", "intermediate"),
  q("sq-ex1-27", "professional_development", "patient_communication", "A patient asks you a question about their prognosis that you feel is outside your scope to answer.", "How would you handle a clinical question outside your scope?", "I would be honest that this question is best answered by their physician. I would say, 'That is an important question, and I want to make sure you get the most accurate answer. Let me arrange for your doctor to discuss this with you.' I would not provide information that could be misleading and would ensure the physician addresses the patient's concern promptly.", "Knowing scope limitations while ensuring patient questions get answered.", "beginner"),
  q("sq-ex1-28", "career_navigation", "job_offer_negotiation", "You are offered a position but the orientation program seems much shorter than recommended for new graduates.", "How would you negotiate for adequate orientation time?", "I would express my concern directly: 'I am very excited about this position. I want to set myself up for success and provide the best care possible. I have researched that new graduate orientation programs typically range from 8-12 weeks. Could we discuss extending the orientation to ensure I have adequate preparation?' I would emphasize that thorough orientation reduces turnover and improves patient safety.", "Framing orientation requests in terms of patient safety and facility investment.", "intermediate"),
  q("sq-ex1-29", "career_navigation", "probation_period", "You discover that a unit policy has recently changed, but no one informed you during your orientation.", "How would you handle discovering you have been following an outdated policy?", "I would immediately update my practice to comply with the current policy. I would review the new policy thoroughly and ask for clarification on anything I do not understand. I would inform my preceptor or charge nurse about the gap in my orientation. I would also check for other policy updates I might have missed. I would not blame anyone but would advocate for better policy communication processes.", "Proactive self-correction and communication gap identification.", "beginner"),
  q("sq-ex1-30", "career_navigation", "career_advancement", "You want to build a professional network as a new nurse but feel awkward about networking.", "How would you start building professional connections?", "I would start small by connecting with colleagues on my own unit and getting involved in unit committees. I would join professional nursing organizations and attend their local meetings. I would seek out a formal or informal mentor. I would attend nursing conferences and continuing education events. Social media platforms like LinkedIn can also be valuable for professional networking. The key is being genuine and showing interest in others.", "Authentic relationship-building rather than transactional networking.", "beginner"),
  q("sq-ex1-31", "workplace_scenarios", "prioritization", "During a code blue on your unit, you have your own patients who still need care.", "How would you manage your patients during a code on the unit?", "I would quickly assess whether my patients are stable and safe. If I have specific skills needed in the code, I would delegate monitoring of my patients to a colleague and participate. If my patients need attention, I would provide their care while being available to assist if called. I would communicate with the charge nurse about coverage and ensure all patient needs are documented.", "Balancing emergency response with ongoing patient care responsibilities.", "intermediate"),
  q("sq-ex1-32", "workplace_scenarios", "patient_safety", "You are about to discharge a patient and realize the pharmacy has sent home medications with conflicting instructions.", "How would you handle conflicting medication instructions at discharge?", "I would hold the discharge until the discrepancy is resolved. I would contact the pharmacy and the prescribing provider to clarify the correct instructions. I would review all discharge medications against the medication reconciliation. I would not send a patient home with confusing or conflicting information. I would document the clarification and provide clear, written instructions.", "Never discharge with unresolved medication discrepancies.", "intermediate"),
  q("sq-ex1-33", "clinical_transition", "critical_thinking_drills", "A patient's BNP level comes back at 1500 pg/mL. Their only diagnosis is pneumonia.", "What could an elevated BNP suggest in a pneumonia patient?", "An elevated BNP of 1500 suggests possible underlying or concurrent heart failure. While BNP can be mildly elevated with pulmonary conditions, a level this high warrants cardiac evaluation. I would assess for heart failure symptoms including edema, jugular venous distension, orthopnea, and weight gain. I would notify the provider, anticipate an echocardiogram order, and monitor fluid balance closely.", "Connecting lab values to differential diagnoses beyond the primary diagnosis.", "advanced"),
  q("sq-ex1-34", "professional_development", "ethical_dilemmas", "A patient tells you they are going to leave against medical advice but asks you not to tell the physician.", "How would you handle a patient wanting to leave AMA without physician notification?", "I would explain that I am obligated to inform the physician when a patient wants to leave AMA, as this is a patient safety and documentation requirement. I would explore why they want to leave—there may be addressable concerns. I would explain the risks of leaving against medical advice. If they insist, I would ensure the AMA form is signed, provide discharge instructions, and document everything.", "Cannot withhold information about AMA from the medical team.", "intermediate"),
  q("sq-ex1-35", "career_navigation", "performance_evaluation", "Your manager suggests you need to develop stronger critical thinking skills.", "How would you develop clinical critical thinking?", "I would engage in deliberate practice by reflecting on clinical scenarios after each shift—what went well, what I would do differently. I would study case studies and participate in clinical simulations. I would ask experienced nurses about their reasoning process when making clinical decisions. I would use resources like clinical reasoning frameworks and evidence-based decision trees to structure my thinking.", "Deliberate practice and structured reflection build critical thinking.", "intermediate"),
  q("sq-ex1-36", "interview_preparation", "behavioral", "Describe a time when you had to adapt your communication style for different audiences.", "How do you adjust your communication for different people?", "During clinical, I cared for a patient whose spouse was a physician and whose adult child had no medical background. When discussing the care plan with the spouse, I used clinical terminology and discussed evidence. With the adult child, I used simple language and analogies. With the patient, I used a warm, reassuring tone and focused on how they were feeling. Adjusting communication to the audience ensures understanding and builds trust.", "Demonstrates communication versatility and audience awareness.", "beginner"),
  q("sq-ex1-37", "interview_preparation", "behavioral", "Tell me about a time you showed initiative in your clinical experience.", "Describe a situation where you went beyond what was expected.", "I noticed that our unit's patient education materials for diabetic foot care were outdated. Without being asked, I researched current guidelines, created updated patient education handouts with clear illustrations, had them reviewed by the diabetes educator, and presented them at our unit meeting. The materials were adopted by the unit and included in the discharge packet. My preceptor noted this initiative in my final evaluation.", "Specific example of proactive improvement beyond assigned duties.", "beginner"),
  q("sq-ex1-38", "workplace_scenarios", "interdisciplinary_communication", "During rounds, the physician dismisses the nursing assessment and makes a decision you believe is based on incomplete information.", "How would you advocate during rounds when your assessment is dismissed?", "I would respectfully but firmly restate my concern with specific data: 'I want to make sure we consider that the patient's output has decreased significantly and their creatinine has been trending up. Given these findings, I am concerned about acute kidney injury.' I would use clinical data to support my position. If still dismissed and I believe patient safety is at risk, I would escalate to the charge nurse or attending.", "Assertive advocacy using clinical data during interprofessional rounds.", "advanced"),
  q("sq-ex1-39", "clinical_transition", "first_shift", "On your first shift, a patient asks you: 'Are you new? Have you ever done this before?'", "How would you respond to a patient questioning your experience?", "I would be honest while being reassuring: 'I am a new graduate, and I want you to know that I am very well-trained and have an experienced team supporting me. Your safety is my top priority. If there is anything you need or are concerned about, please let me know.' Patients appreciate honesty, and most are supportive of new nurses when they show confidence and competence.", "Honest without undermining patient confidence.", "beginner"),
  q("sq-ex1-40", "workplace_scenarios", "medication_error", "A patient received their morning medications from the night nurse, and you are about to give the same medications again because it was not documented.", "How would you prevent a duplicate medication administration?", "Before administering any medication, I would always check the MAR for documentation of recent administration. If there is a question about whether medications were given, I would check with the night nurse, review the medication dispensing system logs, and assess the patient's clinical status. I would hold the medications until I could confirm they had not already been given. I would document my findings and report the documentation gap.", "Always verify before administering—double doses can be dangerous.", "beginner"),
  q("sq-ex1-41", "interview_preparation", "clinical_judgment", "A patient on a heparin drip develops sudden onset severe headache, vomiting, and altered consciousness.", "What emergency do you suspect and what are your immediate actions?", "These symptoms in a patient on anticoagulation suggest possible intracranial hemorrhage. I would immediately stop the heparin drip, perform a rapid neurological assessment including Glasgow Coma Scale, call a code stroke or rapid response, and prepare for emergent CT scan. I would maintain the airway, elevate the head of the bed, and anticipate orders for protamine sulfate to reverse anticoagulation.", "Immediate recognition of potential intracranial bleed with anticoagulant reversal readiness.", "advanced"),
  q("sq-ex1-42", "interview_preparation", "scenario_responses", "A patient is nearing the end of life and asks you about what dying feels like.", "How would you discuss the dying process with a patient?", "I would sit with the patient and ask what specifically they are wondering about. I would provide honest, gentle information about what they might experience: gradual changes in breathing patterns, decreased appetite and thirst, more time sleeping, and peaceful transition. I would reassure them about comfort measures we would provide. I would ask if they would like chaplain or social work support and ensure their emotional and spiritual needs are addressed.", "Honest, compassionate education about the dying process.", "advanced"),
  q("sq-ex1-43", "workplace_scenarios", "handoff_communication", "You need to give report to a float nurse who is unfamiliar with your unit's patient population.", "How would you adjust your handoff for an unfamiliar nurse?", "I would provide more context than usual, including unit-specific protocols, equipment locations, and the general patient population. I would highlight which patients are highest acuity and what to watch for. I would provide my phone number or extension in case they have questions during the shift. I would introduce them to the CNA and other team members. I would ensure they know how to access charge nurse support.", "Extra context and resource identification for unfamiliar nurses.", "intermediate"),
  q("sq-ex1-44", "clinical_transition", "time_management", "You are consistently staying late because you do not start your medication pass until after all assessments are complete.", "How could you restructure your workflow for better efficiency?", "I would combine my assessment rounds with my medication pass instead of doing them separately. When I enter a room for assessment, I would bring the patient's scheduled medications. This clustering approach reduces the number of trips and saves significant time. I would prepare medications before entering each room and use a systematic approach moving from room to room.", "Clustering care activities is one of the most effective time management strategies.", "beginner"),
  q("sq-ex1-45", "professional_development", "patient_communication", "A patient is crying and you are unsure whether to stay silent or speak.", "How do you support a patient who is crying?", "I would stay present with the patient—sometimes the most therapeutic thing is simply being there. I would offer a tissue, sit down if possible, and give them time. When appropriate, I might say, 'I am here with you. Take all the time you need.' I would not rush them or try to fix their emotions. I would assess whether they need any additional support such as social work or chaplain services.", "Therapeutic presence and comfortable silence are powerful nursing interventions.", "beginner"),
  q("sq-ex1-46", "interview_preparation", "behavioral", "Tell me about a time when technology failed and you had to find an alternative solution.", "Describe how you handled a technology failure in a clinical setting.", "During a clinical shift, the electronic medication scanning system went down. Instead of waiting for IT to fix it, I switched to the downtime medication verification process—manually checking the medication label against the printed MAR using the five rights. I double-checked each medication with another nurse before administering. I documented the downtime and entered all data once the system was restored.", "Adaptability and knowledge of backup procedures when technology fails.", "intermediate"),
  q("sq-ex1-47", "workplace_scenarios", "patient_safety", "You notice that a patient's IV infiltration has gone unnoticed and their arm is significantly swollen.", "How would you manage a significant IV infiltration?", "I would immediately stop the infusion and disconnect the IV. I would assess the extent of the infiltration including swelling, skin color, temperature, and sensation. I would elevate the affected extremity and apply warm or cold compresses depending on the infiltrated solution. I would notify the provider, especially if a vesicant was infiltrating. I would establish a new IV site in a different location and document the infiltration using a standardized grading scale.", "Immediate intervention, proper assessment, and documentation of infiltration grade.", "intermediate"),
  q("sq-ex1-48", "clinical_transition", "new_nurse_anxiety", "Your colleagues seem to form friendships easily, but you feel like an outsider on the unit.", "How would you cope with feeling socially isolated at work?", "I would remind myself that forming workplace relationships takes time, especially on established teams. I would make small efforts—bringing treats occasionally, offering to help colleagues, and engaging in break room conversations. I would focus on being a reliable, helpful team member, which naturally builds trust. I would not isolate myself further. If the isolation felt targeted, I would discuss it with my manager.", "Natural relationship-building through reliability and small social gestures.", "beginner"),
  q("sq-ex1-49", "career_navigation", "career_advancement", "You are interested in traveling nursing but are unsure if one year of experience is enough.", "How would you evaluate your readiness for travel nursing?", "One year is typically the minimum requirement for travel nursing agencies, but readiness involves more than time. I would assess my clinical competency across different patient populations, my confidence with independent decision-making, and my adaptability to new environments. I would research agencies thoroughly, start with travel assignments closer to home, and choose facilities with good support systems. I would also consider the financial, licensure, and personal implications.", "Honest readiness assessment beyond just meeting minimum requirements.", "intermediate"),
  q("sq-ex1-50", "interview_preparation", "difficult_interviewer", "The interviewer says: 'We have had problems with new grads who cannot handle the workload. What makes you different?'", "How would you distinguish yourself from other new graduates?", "I would respond with specific evidence rather than general claims: 'I understand your concern. What sets me apart is my deliberate preparation. I consistently received the highest marks in my clinical evaluations for time management and critical thinking. I actively sought out the most challenging clinical placements. I am also committed to this specific unit and have researched your patient population extensively. I am not just looking for any job—I want to build my career here.'", "Specific evidence of competence rather than vague promises.", "advanced"),
  q("sq-ex1-51", "workplace_scenarios", "prioritization", "You receive critical lab results for two patients simultaneously—one with a potassium of 6.5 and one with a hemoglobin of 6.8.", "Which critical lab value would you address first?", "I would prioritize the potassium of 6.5 because hyperkalemia can cause fatal cardiac arrhythmia with minimal warning. I would place the patient on a cardiac monitor immediately and notify the provider. The hemoglobin of 6.8, while serious and requiring transfusion, typically has a slightly longer window for intervention before becoming immediately life-threatening. I would address the hemoglobin immediately after initiating the hyperkalemia protocol.", "Life-threatening cardiac risk takes priority over gradual blood loss.", "advanced"),
  q("sq-ex1-52", "workplace_scenarios", "delegation", "You are the only RN on a small unit with two LPNs and one CNA. A complex patient needs frequent assessments.", "How would you delegate appropriately based on team member scope of practice?", "I would perform all complex assessments, IV medication administration, and care planning for the complex patient myself, as these are within the RN scope. I would delegate vital signs, hygiene care, and routine feeding assistance to the CNA. I would delegate routine medication administration, wound care, and documentation tasks within LPN scope to the LPNs. I would maintain oversight and follow up on all delegated tasks.", "Clear understanding of scope of practice for each team member.", "intermediate"),
  q("sq-ex1-53", "clinical_transition", "documentation_challenges", "You need to document that a patient refused care but they are angry and will not let you explain the documentation.", "How would you document a refusal when the patient is uncooperative?", "I would document the refusal accurately: what was offered, the patient's response, any education provided about risks of refusal, and the patient's emotional state. I would not need the patient's cooperation to document the event. I would note any witnesses present and that the patient was informed of the consequences. I would notify the provider about the refusal and document that notification as well.", "Documentation of refusal does not require patient cooperation or signature.", "intermediate"),
  q("sq-ex1-54", "professional_development", "ethical_dilemmas", "A family member asks you to give a sedative to their confused elderly parent to keep them calm during their visit.", "How would you respond to a family request for inappropriate sedation?", "I would explain that I cannot administer sedation without a medical indication and a physician's order. I would explore why the family wants the patient sedated—perhaps the patient's behavior is distressing to them. I would suggest alternative approaches like creating a calm environment, using therapeutic communication, or involving recreational therapy. If the patient's confusion is causing safety concerns, I would discuss appropriate interventions with the provider.", "Medication cannot be given for family convenience—only for medical indication.", "intermediate"),
  q("sq-ex1-55", "career_navigation", "probation_period", "Your colleagues seem to have a faster pace than you during your probation period.", "How would you address feeling slower than your colleagues?", "I would focus on safety and accuracy rather than trying to match the speed of experienced nurses. I would identify specific areas where I can safely increase my pace—like medication preparation and documentation. I would ask efficient colleagues to share their workflow strategies. I would set incremental speed goals while never compromising patient safety. Speed comes naturally with repetition and confidence.", "Safety-first mindset while actively working on efficiency.", "beginner"),
  q("sq-ex1-56", "interview_preparation", "clinical_judgment", "A patient develops sudden shortness of breath and pleuritic chest pain after a long period of immobility.", "What condition do you suspect and what are your nursing priorities?", "These symptoms suggest pulmonary embolism, especially given the immobility risk factor. My priorities would be to keep the patient calm and in a high Fowler's position, apply oxygen, obtain vital signs including SpO2, establish IV access if not present, and notify the provider immediately for emergent workup including CT pulmonary angiography. I would prepare for possible anticoagulation and monitor for hemodynamic instability.", "Rapid recognition of PE risk factors and emergent assessment priorities.", "advanced"),
  q("sq-ex1-57", "workplace_scenarios", "interdisciplinary_communication", "A physical therapist disagrees with your assessment that the patient is too unstable for ambulation.", "How would you resolve a clinical disagreement with another discipline?", "I would share my specific concerns with objective data: recent vital signs, orthostatic changes, sedation level, or other clinical findings. I would invite the PT to review the data together and come to a shared decision. If we still disagreed, we would consult the physician for guidance. Patient safety is the shared goal, and both perspectives have value. I would document the communication and the agreed-upon plan.", "Data-driven collaborative decision-making across disciplines.", "intermediate"),
  q("sq-ex1-58", "professional_development", "advocacy", "A patient with a disability is not receiving accommodations for their condition during their hospitalization.", "How would you advocate for disability accommodations?", "I would assess what specific accommodations the patient needs—assistive devices, communication aids, accessible equipment, or environmental modifications. I would document these needs in the care plan and communicate them to the entire care team. I would contact appropriate departments such as occupational therapy, social work, or patient relations. I would ensure that the patient's dignity and independence are maintained throughout their stay.", "Proactive assessment and advocacy for disability accommodations.", "intermediate"),
  q("sq-ex1-59", "clinical_transition", "critical_thinking_drills", "A patient's WBC count jumps from 8,000 to 18,000 overnight.", "What does a rapidly rising WBC count suggest?", "A rapid rise in WBC count from normal to 18,000 suggests an acute inflammatory or infectious process. I would assess for signs of infection including fever, localized symptoms (redness, swelling, drainage at surgical or IV sites), and changes in vital signs. I would review the patient's clinical context—are they post-operative, immunocompromised, or on any medications that could affect WBC? I would notify the provider and anticipate orders for blood cultures and possibly imaging.", "Connecting lab trends to clinical assessment and anticipating diagnostic workup.", "intermediate"),
  q("sq-ex1-60", "career_navigation", "performance_evaluation", "Your evaluation mentions that you need to participate more in unit meetings and quality improvement.", "How would you increase your professional engagement on the unit?", "I would volunteer for a quality improvement project that interests me and aligns with my strengths. I would attend unit meetings consistently and prepare thoughtful questions or contributions. I would join or start a journal club. I would offer to present a case study or clinical topic to the team. Active participation shows investment in the unit and contributes to professional development.", "Specific, actionable ways to increase professional visibility and contribution.", "beginner"),
  q("sq-ex1-61", "interview_preparation", "behavioral", "Tell me about a time when you had to manage multiple competing priorities successfully.", "Describe your approach to juggling multiple demands.", "During a busy clinical shift, I had a patient who needed a blood transfusion started, another who needed post-op teaching before discharge, and a third whose family was waiting for an update. I prioritized by starting the blood transfusion first as it was time-sensitive, then called the family with a brief update while the transfusion was running, and finally completed the discharge teaching. I delegated vital sign monitoring to the CNA and communicated my plan to the charge nurse.", "Clear prioritization strategy with delegation and communication.", "intermediate"),
  q("sq-ex1-62", "workplace_scenarios", "patient_safety", "During a fire drill, you realize one of your patients is on a ventilator and cannot be easily moved.", "How would you prepare for an emergency evacuation of a ventilator patient?", "I would know my unit's fire evacuation plan specifically for ventilator patients. During the drill, I would practice securing a manual resuscitation bag, disconnecting the ventilator, and using the bag-valve-mask while moving the patient. I would verify that portable oxygen is available and know the evacuation routes. I would ensure I know how to call respiratory therapy for immediate assistance and coordinate with the team for safe transport.", "Knowledge of emergency procedures for equipment-dependent patients.", "advanced"),
  q("sq-ex1-63", "interview_preparation", "scenario_responses", "A patient being discharged tells you they do not have transportation home.", "How would you help a patient with no transportation at discharge?", "I would not simply discharge the patient without a safe plan. I would contact social work to arrange transportation, explore hospital shuttle services, contact family or friends on the patient's behalf, or arrange for a medical transport service. I would check if the patient qualifies for community transportation assistance programs. I would document the barrier and the solutions arranged. No patient should be discharged without a safe way to get home.", "Addressing social determinants of health that affect safe discharge.", "beginner"),
  q("sq-ex1-64", "clinical_transition", "time_management", "You receive multiple phone calls during medication administration—lab results, physician callbacks, and pharmacy questions.", "How would you manage phone interruptions during critical tasks?", "I would prioritize safety by pausing the medication pass only for truly urgent calls. For non-urgent calls, I would take a quick message and return the call after completing the medication. I would use the unit clerk to screen calls when available. I would establish a system where I check and return calls at designated times between critical tasks. I would never rush through a medication to answer a phone.", "Protecting medication safety from non-urgent interruptions.", "intermediate"),
  q("sq-ex1-65", "professional_development", "workplace_bullying", "You hear a rumor being spread about you that is untrue and damaging to your professional reputation.", "How would you address false rumors about yourself?", "I would not engage with gossip or try to confront the rumor in a group setting. I would address it directly with the person I believe started it, if known: 'I heard something that is not accurate about me, and I wanted to address it with you directly.' If the rumor is affecting my work or reputation, I would document it and discuss it with my manager. I would maintain my professionalism and let my work performance speak for itself.", "Direct address with the source, documentation, and professional composure.", "intermediate"),
  q("sq-ex1-66", "interview_preparation", "common_nursing_interview", "The interviewer asks: 'What questions do you have for us?'", "What thoughtful questions should you ask at the end of an interview?", "I would ask questions that show genuine interest and preparation: 'What does a typical orientation look like for new graduates on this unit? What qualities are most important for success in this role? What is the nurse-to-patient ratio on different shifts? How does the unit support continuing education and professional development? What would you say is the biggest challenge new nurses face on this unit?' These show I am thinking about long-term success, not just getting the job.", "Thoughtful questions demonstrate preparation, genuine interest, and long-term thinking.", "beginner"),
  q("sq-ex1-67", "workplace_scenarios", "medication_error", "You give a PRN medication to a patient who requested it, then realize the patient's identity was not properly verified.", "How would you address a medication given without proper identification verification?", "I would immediately verify the patient's identity using two identifiers. If the medication was given to the correct patient, I would still document the identification lapse and file an incident report. If the medication was given to the wrong patient, I would assess both patients, notify the provider, and follow the medication error protocol. I would implement a personal safeguard to prevent this from recurring.", "Identity verification lapses are serious even when the right patient received the medication.", "intermediate"),
  q("sq-ex1-68", "clinical_transition", "first_shift", "You complete your first shift and feel like you did not do a great job.", "How would you process a disappointing first shift?", "I would remind myself that feeling inadequate after the first shift is nearly universal among new nurses. I would objectively evaluate what went well and what I would improve. I would talk to my preceptor or a trusted colleague about my concerns. I would write down specific lessons learned and goals for my next shift. I would practice self-compassion and remember that competence develops over time, not overnight.", "Self-reflection, self-compassion, and actionable goal-setting after difficult experiences.", "beginner"),
  q("sq-ex1-69", "career_navigation", "job_offer_negotiation", "The interviewer asks about your availability and you have a previously planned vacation coming up.", "How would you handle disclosing pre-planned time off during the hiring process?", "I would disclose the planned time off early in the negotiation process, ideally after receiving the offer but before accepting. I would say, 'I am very excited about this opportunity. I want to be transparent that I have a previously planned commitment on these dates. I am happy to work this into the schedule and am flexible about other scheduling needs.' Being upfront shows integrity, and most employers appreciate honesty.", "Transparency about pre-existing commitments during negotiation.", "beginner"),
  q("sq-ex1-70", "interview_preparation", "panel_interview", "During a panel interview, a staff nurse asks you a very technical clinical question that you do not know the answer to.", "How would you handle not knowing an answer during a panel interview?", "I would be honest: 'That is a great question, and I want to be transparent that I am not certain of the exact answer. Based on my clinical knowledge, I believe the approach would involve [best guess], but I would verify this against current guidelines or consult with an experienced colleague before acting on it in practice.' Admitting gaps while showing your reasoning process is more impressive than guessing.", "Honesty about knowledge gaps combined with safe clinical reasoning approach.", "intermediate"),
];
